(52, 'Las Vegas Live 2014', NULL, '4', '2014.12.19.', 'Universal', 'Alternative Rock;Gothic Metal;Gothic Rock;Pop Rock', 'Las Vegas Live 2014 is a live record by HIM which came out on December 19, 2014.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Drums~Keyboard‚†Ä‚ÄĘ‚†ÄPiano', NULL, '447', '21‚Ė†22‚Ė†23‚Ė†27‚Ė†28', '', '~Unleash the Red~[{22}]‚Ė†~The Sacrament~[{22}]‚Ė†~Razorblade Kiss~[{4_Bnd};{22}]‚Ė†~Pretending~[{22}]‚Ė†~Right Here in My Arms~[{22}]‚Ė†~This Fortress of Tears~[{22}]‚Ė†~Your Sweet Six Six Six~[{22}]‚Ė†~Wicked Game~[{Chris Isaak_not_found}]‚Ė†~Gone with the Sin~[{22}]‚Ė†~Soul on Fire~[{22}]‚Ė†~Heartache Every Moment~[{22}]‚Ė†~Rip Out the Wings of a Butterfly~[{22}]‚Ė†~The Kiss of Dawn~[{22}]‚Ė†~In Joy and Sorrow~[{22}]‚Ė†~Poison Girl~[{22}]‚Ė†~Killing Loneliness~[{22}]‚Ė†~No Love~[{22}]‚Ė†~Join Me in Death~[{22}]‚Ė†~Buried Alive by Love~[{22}]‚Ė†~When Love and Death Embrace~[{22}]‚Ė†~Rebel Yell~[{22}]‚Ė†~.12.19. Las Vegas Live 2014~[{HIM_not_found}]', NULL, NULL),
(54, 'When Love and Death Embrace', NULL, '4', '1997.10.16.', 'BMG', 'Alternative Rock', 'When Love and Death Embrace is a single by HIM which came out on October 16, 1997, taken from their album Greatest Lovesongs Vol. 666 released in 1997.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Keyboard~Drums', NULL, '447', '21‚Ė†22‚Ė†23‚Ė†24‚Ė†25', '48235c2f-8117-4f4b-b791-9351872c2e27', '~When Love and Death Embrace~[{22}]', NULL, NULL),
(55, 'Your Sweet Six Six Six', NULL, '4', '1998.02.02.', 'BMG', 'Heavy Metal', 'Your Sweet Six Six Six is a single by HIM which came out on February 02, 1998, taken from their album Greatest Lovesongs Vol. 666 released in 1997.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Keyboard~Drums', NULL, '447', '21‚Ė†22‚Ė†23‚Ė†24‚Ė†25', 'd9738723-d46c-4d5d-93ef-6ee4af0626e2', '~The Beginning of the End~[{22}]‚Ė†~Your Sweet Six Six Six~[{22}]', NULL, NULL),
(56, 'Wicked Game', NULL, '4', '1998.09.28.', 'BMG', 'Pop Rock', 'Wicked Game is a song by American rock musician Chris Isaak from his third album Heart Shaped World (1989). It was released as a single to little attention in July 1989; the song became a sleeper hit when Lee Chestnut, an Atlanta radio station music director who loved David Lynch films, began broadcasting it after hearing it in Lynchs film Wild at Heart (1990). The song quickly became an American top 10 hit in March 1991, reaching No. 6 on the Billboard Hot 100. It also became a No. 1 hit in Belgium and reached the top 10 in several other countries.\nWicked Game has been covered by a wide variety of musicians and has been featured in numerous films, television series, and commercials, to the point that Dazed magazine questioned whether it might be the most influential love song in modern music. It subsequently received retrospective critical acclaim, being listed in the 2010 book 1001 Songs You Must Hear Before You Die and the updated edition of the 1989 book The Heart of Rock & Soul: The 1001 Greatest Singles Ever Made.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Keyboard~Drums', NULL, '447', '21‚Ė†22‚Ė†23‚Ė†24‚Ė†25', 'b580eda8-5d3f-43b0-9a58-3732cdb81b43', '~Wicked Game~[{Chris Isaak_not_found}]‚Ė†~For You~[{23};{22}]‚Ė†~Our Diabolikal Rapture~[{Teemu J√§rvinen_not_found};{23};{22}]', NULL, NULL),
(57, 'It‚ĖÄs All Tears (Drown in This Love)', NULL, '4', '1999.03.01.', 'BMG', 'Alternative Rock;Gothic Metal;Gothic Rock;Pop Rock', 'Its All Tears (Drown in This Love) is a single by HIM which came out on March 01, 1999, taken from their album Greatest Lovesongs Vol. 666 released in 1997.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Keyboard~Drums', NULL, '469', '21‚Ė†22‚Ė†23‚Ė†26‚Ė†27', 'fc66dd4e-7c68-4de8-b4f8-0d07f032d073', '~The Heartless~[{22}]‚Ė†~It‚ĖÄs All Tears (Drown in This Love)~[{22}]', NULL, NULL),
(58, 'Join Me in Death', NULL, '4', '1999.11.29.', 'BMG', 'Alternative Rock;Gothic Metal;Gothic Rock;Pop Rock', 'Join Me in Death is a single by Finnish gothic rock band HIM, taken from their second studio album, Razorblade Romance (2000). It was also released under the condensed title of Join Me. The song is the eighth-best-selling single of all time in Finland.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Keyboard~Drums', NULL, '469', '21‚Ė†22‚Ė†23‚Ė†26‚Ė†27', '', '~Join Me in Death~[{22}]‚Ė†~It‚ĖÄs All Tears (Drown in This Love)~[{22}]‚Ė†~Rebel Yell~[{22}]', NULL, NULL),
