(76, 'Killing Loneliness', NULL, '4', '2006.03.02.', 'Sire', 'Alternative Rock;Gothic Metal;Gothic Rock;Pop Rock', 'Killing Loneliness is a song by Finnish rock band HIM. It was released in February 2006, as a single from their 2005 breakthrough album, Dark Light. Killing Loneliness, along with Wings of a Butterfly, is one of the bands best known songs in the United States.\nOn the 11 May 2006 episode of Loveline, lead vocalist Ville Valo confirmed that the song was inspired by skateboarder Brandon Novak, who blamed his heroin addiction on a need to, as he put it, kill the loneliness. The song is playable in the 2010 video game Rock Band 3.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Drums~Keyboard‚†Ä‚ÄĘ‚†ÄPiano', NULL, '471', '21‚Ė†22‚Ė†23‚Ė†27‚Ė†28', '90e75b41-c94f-40c8-a120-de432ebd767e', '~Killing Loneliness~[{22}]‚Ė†~Under the Rose~[{22}]‚Ė†~Rip Out the Wings of a Butterfly~[{22}]‚Ė†~Play Dead~[{22}]‚Ė†~Vampire Heart~[{22}]‚Ė†~The Cage~[{22}]‚Ė†~Venus (In Our Blood)~[{22}]‚Ė†~Under the Rose ~[{22}]', NULL, NULL),
(77, 'Under the Rose', NULL, '4', '2006.06.06.', 'Sire', 'Alternative Rock;Gothic Metal;Gothic Rock;Pop Rock', 'Under the Rose is a single by HIM which came out on June 06, 2006, taken from their album Dark Light released in 2005.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Drums~Keyboard‚†Ä‚ÄĘ‚†ÄPiano', NULL, '471', '21‚Ė†22‚Ė†23‚Ė†27‚Ė†28', '4669cadc-a14f-4223-9947-bf8078ee0763', '~Under the Rose~[{22}]', NULL, NULL),
(78, 'The Kiss of Dawn', NULL, '4', '2007.08.28.', 'Sire', 'Heavy Metal', 'The Kiss of Dawn is a song by Finnish band HIM. It is the fourth track from the bands sixth studio album Venus Doom (2007), and was released on 28 July 2007 as the albums lead single.', 'Bass‚†Ä‚ÄĘ‚†ÄDouble Bass~Lead Vocals‚†Ä‚ÄĘ‚†ÄGuitar~Guitar~Drums~Keyboard‚†Ä‚ÄĘ‚†ÄPiano', NULL, '447', '21‚Ė†22‚Ė†23‚Ė†27‚Ė†28', 'dd1c7cbe-c3ec-4e75-8736-de3932eea149', '~The Kiss of Dawn~[{22}]‚Ė†~Venus Doom~[{22}]‚Ė†~Passion‚ĖÄs Killing Floor~[{22}]‚Ė†~Love in Cold Blood~[{22}]', NULL, NULL),
